import { webcrypto } from 'node:crypto';
import { signaturePublicKeyJWK } from '../../../common/core/service/keys.js';
let signaturePublicKey;
export const getSignaturePublicKey = async () => {
    signaturePublicKey ??= await webcrypto.subtle.importKey('jwk', signaturePublicKeyJWK, { name: 'ECDSA', namedCurve: 'P-256' }, false, ['verify']);
    return signaturePublicKey;
};
